// src/services/api.js
// Handles all HTTP requests to the backend

import axios from "axios";

const BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

/**
 * Preview the generated assignment (returns JSON text)
 * @param {File} file - The .docx file
 * @param {string} studentName
 * @param {string} enrollment
 * @returns {Promise<{studentName, enrollment, generatedContent, wordCount}>}
 */
export async function previewAssignment(file, studentName, enrollment) {
  const formData = new FormData();
  formData.append("file", file);
  formData.append("studentName", studentName);
  formData.append("enrollment", enrollment);

  const response = await axios.post(`${BASE_URL}/preview`, formData, {
    headers: { "Content-Type": "multipart/form-data" },
    timeout: 120000, // 2 min — HF models can be slow on cold start
  });

  if (!response.data.success) {
    throw new Error(response.data.error || "Preview failed");
  }

  return response.data;
}

/**
 * Generate and download the completed assignment as a .docx
 * @param {File} file
 * @param {string} studentName
 * @param {string} enrollment
 */
export async function downloadAssignment(file, studentName, enrollment) {
  const formData = new FormData();
  formData.append("file", file);
  formData.append("studentName", studentName);
  formData.append("enrollment", enrollment);

  const response = await axios.post(`${BASE_URL}/generate`, formData, {
    headers: { "Content-Type": "multipart/form-data" },
    responseType: "blob",    // <-- Important: tells axios to return binary data
    timeout: 180000,         // 3 min
  });

  // Create a download link from the blob
  const blob = new Blob([response.data], {
    type: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
  });

  const url = window.URL.createObjectURL(blob);
  const safeName = studentName.replace(/[^a-z0-9]/gi, "_").toLowerCase();
  const filename = `assignment_${safeName}_${enrollment}.docx`;

  const link = document.createElement("a");
  link.href = url;
  link.setAttribute("download", filename);
  document.body.appendChild(link);
  link.click();
  link.parentNode.removeChild(link);
  window.URL.revokeObjectURL(url);

  return filename;
}
